'use client';
import { HostCategory } from '@/types';
import { motion } from 'framer-motion';
import { Layers, ScrollText, Pencil, Trash2 } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/Card';
import { Button } from '@/components/ui/button';

interface CategorieCardProps {
  index: number;
  categorie: HostCategory;
  onEdit?: () => void;
  onDelete?: () => void;
}

const CategorieCard = ({
  index,
  categorie,
  onEdit,
  onDelete,
}: CategorieCardProps) => {
  return (
    <motion.div
      key={categorie._id}
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.05 }}
      whileHover={{ scale: 1.03 }}
    >
      <Card className='bg-white border-2 border-purple-300 rounded-xl shadow-md hover:shadow-purple-400 transition-all duration-300'>
        <CardContent className='p-5 space-y-3'>
          <div className='flex items-center justify-between'>
            <h3 className='text-xl font-bold text-purple-800'>
              {categorie.name}
            </h3>
            <Layers
              className='text-purple-400'
              size={22}
            />
          </div>

          <div className='text-gray-600 text-sm flex items-start gap-2'>
            <ScrollText
              className='text-blue-400 mt-1'
              size={18}
            />
            <p className='leading-relaxed'>{categorie.description}</p>
          </div>

          {/* أزرار الأدمن فقط إذا كانت موجودة */}
          {(onEdit || onDelete) && (
            <div className='flex justify-end gap-2 pt-4 border-t border-gray-200 mt-3'>
              {onEdit && (
                <Button
                  variant='outline'
                  size='sm'
                  onClick={onEdit}
                  className='flex items-center gap-1 text-purple-600 border-purple-300 hover:bg-purple-50'
                >
                  <Pencil size={16} />
                  Edit
                </Button>
              )}
              {onDelete && (
                <Button
                  variant='destructive'
                  size='sm'
                  onClick={onDelete}
                  className='flex items-center gap-1'
                >
                  <Trash2 size={16} />
                  Delete
                </Button>
              )}
            </div>
          )}
        </CardContent>
      </Card>
    </motion.div>
  );
};

export default CategorieCard;
